return ['x-generator'=>'GlotPress/4.0.1','translation-revision-date'=>'2023-01-28 20:18:08+0000','plural-forms'=>'nplurals=2; plural=n != 1;','project-id-version'=>'Plugins - WP Debugging - Stable (latest release)','language'=>'sv_SE','messages'=>['Menu itemWP Debugging'=>'WP-felsökning','The <strong>WP Debugging</strong> plugin must have a <code>wp-config.php</code> file that is writable by the filesystem.'=>'Tillägget <strong>WP Debugging</strong> kräver att filsystemet tillåter skrivning till filen <code>wp-config.php</code>.','Settings'=>'﻿Inställningar','<strong>Please note:</strong> Your <code>wp-config.php</code> file must be writable by the filesystem. Any errors will result in a PHP Exception being thrown. Debug constants as documented in <a href="https://wordpress.org/documentation/article/debugging-in-wordpress/">Debugging in WordPress</a>.'=>'<strong>Observera:</strong> Filsystemet måste tillåta skrivning till filen <code>wp-config.php</code>. Eventuella fel kommer att resultera i att ett PHP-fel uppstår. Felsök konstanter enligt <a href="https://wordpress.org/documentation/article/debugging-in-wordpress/">felsökning i WordPress</a>.','Select the debugging constants.'=>'Välj felsökningskonstanterna.','The following constants are set with plugin activation and removed with plugin deactivation.'=>'Följande konstanter anges vid aktivering av tillägget och tas bort vid inaktivering.','Set WP_DISABLE_FATAL_ERROR_HANDLER to true.'=>'Ange WP_DISABLE_FATAL_ERROR_HANDLER till ”true”.','Set WP_DEBUG_DISPLAY to false, default is true.'=>'Ange WP_DEBUG_DISPLAY till ”false”, standard är ”true”.','Set WP_DEBUG to true.'=>'Ange WP_DEBUG till ”true”.','Debugging Constants'=>'Felsökningskonstanter','Saved.'=>'Sparat.','Andy Fragen'=>'Andy Fragen','A support/troubleshooting plugin for WordPress.'=>'Ett support-/felsökningstillägg för WordPress.','https://github.com/afragen/wp-debugging'=>'https://github.com/afragen/wp-debugging','WP Debugging'=>'WP Debugging']];